/**
 * Route recipe templates — index, handler, and test file content.
 */

import { toPascalCase, toCamelCase } from '../generators/utils.js';

export function indexTemplate(name: string): string {
  const pascal = toPascalCase(name);
  const camel = toCamelCase(name);
  return `/**
 * @generated by @flusk/cli
 * ${pascal} routes — registration entrypoint
 */

import type { FastifyInstance } from 'fastify';
import { register${pascal}Handlers } from './${name}.js';

export async function ${camel}Routes(
  fastify: FastifyInstance,
): Promise<void> {
  register${pascal}Handlers(fastify);
}
`;
}

export function handlerTemplate(name: string): string {
  const pascal = toPascalCase(name);
  return `/**
 * @generated by @flusk/cli
 * ${pascal} route handlers
 */

import type { FastifyInstance } from 'fastify';
import { Type } from '@sinclair/typebox';
import { getLogger } from '@flusk/logger';

const log = getLogger().child({ module: '${name}-routes' });

export function register${pascal}Handlers(
  fastify: FastifyInstance,
): void {
  fastify.get('/', {
    schema: {
      response: { 200: Type.Object({ status: Type.String() }) },
    },
  }, async (request) => {
    log.info({ url: request.url }, '${name} request');
    // CUSTOM:START — add route logic
    return { status: 'ok' };
    // CUSTOM:END
  });
}
`;
}

export function testTemplate(name: string): string {
  const pascal = toPascalCase(name);
  return `/**
 * @generated by @flusk/cli
 */
import { describe, it, expect } from 'vitest';

describe('${pascal} routes', () => {
  it('should export handler registration', async () => {
    const mod = await import('./${name}.js');
    expect(mod.register${pascal}Handlers).toBeDefined();
  });
});
`;
}
